const IMGS = {
  flora_fachada: "data:image/jpeg;base64,",
  flora_interior_1: "data:image/jpeg;base64,",
  flora_interior_2: "data:image/jpeg;base64,",
  apt_living: "data:image/jpeg;base64,",
  apt_cozinha: "data:image/jpeg;base64,",
  apt_sala: "data:image/jpeg;base64,",
};

// Injeta as imagens nos elementos após o carregamento da página
document.addEventListener('DOMContentLoaded', function() {
  document.getElementById('img-flora-fachada').src = IMGS.flora_fachada;
  document.getElementById('img-flora-int1').src    = IMGS.flora_interior_1;
  document.getElementById('img-flora-int2').src    = IMGS.flora_interior_2;
  document.getElementById('img-apt-living').src    = IMGS.apt_living;
  document.getElementById('img-apt-cozinha').src   = IMGS.apt_cozinha;
  document.getElementById('img-apt-sala').src      = IMGS.apt_sala;
});
